import{_ as t,o as a,c as o,a3 as n}from"./chunks/framework.BveOjhN0.js";const u=JSON.parse('{"title":"Tenant RBAC — Developer Guide","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Tenant RBAC — Developer Guide | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/developer-guide/tenant-rbac"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Tenant RBAC — Developer Guide | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/developer-guide/tenant-rbac"}]]},"headers":[],"relativePath":"developer-guide/tenant-rbac.md","filePath":"developer-guide/tenant-rbac.md","lastUpdated":1784902400000}'),s={name:"developer-guide/tenant-rbac.md"};function i(r,e,d,c,l,p){return a(),o("div",null,[...e[0]||(e[0]=[n(`<h1 id="tenant-rbac-—-developer-guide" tabindex="-1">Tenant RBAC — Developer Guide <a class="header-anchor" href="#tenant-rbac-—-developer-guide" aria-label="Permalink to &quot;Tenant RBAC — Developer Guide&quot;">​</a></h1><p>Workspace (tenant) authorization is isolated per workspace: users, roles, and role↔permission assignments never cross tenant boundaries. Permissions are a shared vocabulary on the <code>tenant-api</code> guard; roles are scoped with <code>roles.tenant_id</code>.</p><h2 id="model" tabindex="-1">Model <a class="header-anchor" href="#model" aria-label="Permalink to &quot;Model&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Workspace</span></span>
<span class="line"><span>  → Users (tenant DB / tenancy-scoped users table)</span></span>
<span class="line"><span>  → Roles (central roles table, tenant_id = workspace UUID)</span></span>
<span class="line"><span>  → Permissions (global names on guard tenant-api)</span></span>
<span class="line"><span>  → Application access (policies + middleware)</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Layer</th><th>Concern</th><th>Enforcement</th></tr></thead><tbody><tr><td>Tenancy</td><td>Workspace isolation</td><td>Stancl tenancy + <code>X-Tenant-Domain</code> / host</td></tr><tr><td>Module licensing</td><td>Workspace owns the domain</td><td><code>module:{slug}</code> middleware</td></tr><tr><td>RBAC</td><td>User may act inside that domain</td><td>Spatie <code>can:{permission}</code> / policies</td></tr></tbody></table><p>Both module ownership and permission checks are required for module features:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Workspace owns module? → User has permission? → Allow; otherwise deny</span></span></code></pre></div><p>Core Administration (Users, Roles, Settings) does not require a module subscription; it uses Spatie permissions only.</p><h2 id="isolation-approach" tabindex="-1">Isolation approach <a class="header-anchor" href="#isolation-approach" aria-label="Permalink to &quot;Isolation approach&quot;">​</a></h2><p>Spatie <strong>teams</strong> are not enabled. Isolation uses:</p><ol><li><code>roles.tenant_id</code> set to the workspace UUID when roles are created (provisioning + CRUD).</li><li>Unique index <code>(tenant_id, name, guard_name)</code>.</li><li>Role assignment by <strong>Role model instance</strong> (not bare name), so Spatie attaches the correct row.</li><li>Permission validation: <code>exists:roles,name</code> filtered by current <code>tenant_id</code> + <code>guard_name = tenant-api</code>.</li><li><code>RolePolicy</code> / <code>TenantUserPolicy</code> ensure actors only see/mutate resources in the current workspace.</li></ol><p>Permissions remain a shared vocabulary defined in <code>config/tenant-permissions.php</code> (e.g. <code>users.list</code>, <code>leads.view</code>, <code>communication-templates.use</code>). They are not copied per tenant.</p><p><strong>How permissions reach production:</strong></p><table tabindex="0"><thead><tr><th>Moment</th><th>Mechanism</th></tr></thead><tbody><tr><td>New workspace</td><td><code>TenantAuthorizationProvisioningService::provisionDefaults()</code> during <code>TenantProvisioningService</code></td></tr><tr><td>Existing workspace + new permissions</td><td>Additive <strong>data migration</strong> via <code>TenantPermissionSynchronizer::grantMissingDefaultRolePermissions([...])</code></td></tr><tr><td>Login / dashboard / role listing</td><td><strong>Never</strong> mutates roles or permissions</td></tr></tbody></table><p>Do not run permission seeders in production. Do not <code>syncPermissions()</code> on customized roles during deploy.</p><h3 id="legacy-shared-roles" tabindex="-1">Legacy shared roles <a class="header-anchor" href="#legacy-shared-roles" aria-label="Permalink to &quot;Legacy shared roles&quot;">​</a></h3><p>Workspaces created before isolation may still have users on <code>tenant_id = null</code> roles. Repair is an explicit maintenance operation; authenticated requests never mutate authorization state. Operators run:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tenants:isolate-roles</span></span></code></pre></div><h2 id="owner" tabindex="-1">Owner <a class="header-anchor" href="#owner" aria-label="Permalink to &quot;Owner&quot;">​</a></h2><ul><li>Role name: <code>superadmin</code> (<code>TenantAuthorizationProvisioningService::OWNER_ROLE</code>)</li><li>Created during workspace registration</li><li>Receives all tenant-api permissions</li><li>Protected from deletion (<code>config/tenant-protected-roles.php</code>)</li><li>Cannot access the Central Application (separate guard / user model)</li></ul><p>Default undeletable roles: <code>admin</code>, <code>manager</code>, <code>staff</code> (editable permissions; not deletable).</p><h2 id="api-tenant" tabindex="-1">API (tenant) <a class="header-anchor" href="#api-tenant" aria-label="Permalink to &quot;API (tenant)&quot;">​</a></h2><p>Prefix: <code>/api/tenant/v1</code> · Guard: <code>auth:tenant-api</code></p><table tabindex="0"><thead><tr><th>Resource</th><th>Routes</th></tr></thead><tbody><tr><td>Users</td><td>CRUD + suspend / unsuspend / restore / force-delete / change-password / verify-email / resend-verification</td></tr><tr><td>Roles</td><td>CRUD + clone</td></tr><tr><td>Permissions matrix</td><td><code>GET roles/permissions-matrix</code></td></tr></tbody></table><p>Services: <code>TenantUserService</code>, <code>TenantRoleService</code>. Policies gate every mutating action.</p><h2 id="frontend" tabindex="-1">Frontend <a class="header-anchor" href="#frontend" aria-label="Permalink to &quot;Frontend&quot;">​</a></h2><p>Shared Central pages are reused with <code>getAuthContext()</code>:</p><table tabindex="0"><thead><tr><th>Path</th><th>Page</th></tr></thead><tbody><tr><td><code>/users</code></td><td><code>UsersPage</code> (no Invite; workspace copy)</td></tr><tr><td><code>/roles</code></td><td><code>RolesPage</code></td></tr><tr><td><code>/roles/matrix</code></td><td><code>RolesMatrixPage</code></td></tr></tbody></table><p>Axios uses the tenant API base when the SPA is on a tenant path. Navigation: Administration → Users / Roles (<code>PERMISSIONS.users.list</code> / <code>roles.list</code>).</p><h2 id="tests" tabindex="-1">Tests <a class="header-anchor" href="#tests" aria-label="Permalink to &quot;Tests&quot;">​</a></h2><ul><li>Pest: <code>tests/Feature/Tenant/User/</code>, <code>tests/Feature/Tenant/Role/</code> (CRUD, assignment, isolation, authorization)</li><li>Playwright: <code>npm run test:e2e:tenant-rbac</code></li></ul>`,31)])])}const m=t(s,[["render",i]]);export{u as __pageData,m as default};
